import jwt from 'jsonwebtoken';
import bcrypt from 'bcryptjs';

export interface UserPayload {
  id: string;
  email: string;
  role: string;
}

export class AuthService {
  private readonly secretKey: string;
  private readonly tokenExpiry: string;

  constructor(secretKey: string, tokenExpiry = '24h') {
    this.secretKey = secretKey;
    this.tokenExpiry = tokenExpiry;
  }

  async generateToken(payload: UserPayload): Promise<string> {
    return jwt.sign(payload, this.secretKey, { expiresIn: this.tokenExpiry });
  }

  async verifyToken(token: string): Promise<UserPayload> {
    return jwt.verify(token, this.secretKey) as UserPayload;
  }

  async hashPassword(password: string): Promise<string> {
    return bcrypt.hash(password, 10);
  }
}

